"""## Visualization"""

def show_sample(
    image,
    annots_or_preds,
    orig_size,
    colors=None,
    unnormalize=False,
    mean=None,
    std=None,
    bbox_unnormalize=False,
    rescale=False,
    is_label=True
):
    if isinstance(image, torch.Tensor):
        image = image.numpy().transpose(1, 2, 0)
    elif isinstance(image, Image.Image):
        image = np.array(image)

    if colors is None:
        colors = np.random.randint(0, 255, size=(len(VOC2007_CLASSES), 3), dtype='uint8') / 255.0

    if unnormalize:
        assert mean is not None and std is not None
        image = image * std + mean

    if rescale:
        image = image.astype(np.float32) / 255.0

    box_key = 'boxes'
    label_key = 'class_labels'
    if not is_label:
        label_key = 'labels'

        pred_labels = torch.cat([v["labels"] for v in annots_or_preds])
        pred_boxes = torch.cat([v["boxes"] for v in annots_or_preds])
        annots_or_preds = {
            box_key: pred_boxes,
            label_key: pred_labels
        }

    plt.imshow(image)
    ax = plt.gca()

    for box, class_id in zip(annots_or_preds[box_key], annots_or_preds[label_key]):
        if isinstance(box, torch.Tensor):
            box = box.detach().cpu().numpy()

        if isinstance(class_id, torch.Tensor):
            class_id = class_id.item()

        if bbox_unnormalize:
            cx, cy, w, h = box
            x1 = cx - w / 2
            y1 = cy - h / 2
        else:
            x1, y1, x2, y2 = box

            w = x2 - x1
            h = y2 - y1

        if box.min() >= 0.0 and box.max() <= 1.0 :
            orig_h, orig_w = orig_size
            x1 = x1 * orig_w
            y1 = y1 * orig_h
            w = w * orig_w
            h = h * orig_h

        class_name = VOC2007_CLASSES[class_id]

        rect = patches.Rectangle(
            (x1, y1),
            w, h,
            linewidth=1.5,
            edgecolor=colors[class_id],
            facecolor='none'
        )
        ax.add_patch(rect)
        ax.text(
            x1, y1,
            class_name,
            c='white',
            size=10,
            path_effects=[pe.withStroke(linewidth=2, foreground=colors[class_id])],
            family='sans-serif',
            weight='semibold',
            va='top', ha='left',
            bbox=dict(
                boxstyle='round',
                ec=colors[class_id],
                fc=colors[class_id],
            )
        )

    plt.axis('off')
    plt.show()

