class DetrEncoderLayer(nn.Module):
    def __init__(
        self,
        encoder_ffn_dim,
        encoder_attention_heads,
        d_model,
        dropout=0.1,
    ):
        super().__init__()
        self.embed_dim = d_model
        ##########################################
        # TODO: fill the below incomplete code   #
        ##########################################
        # [START]
        self.self_attn = DetrAttention(
        embed_dim=d_model,
        num_heads=encoder_attention_heads
        )
        self.self_attn_layer_norm = nn.LayerNorm(d_model)
        self.dropout = nn.Dropout(dropout)
        self.activation_fn = nn.ReLU()
        self.fc1 = nn.Linear(d_model, encoder_ffn_dim)
        self.fc2 = nn.Linear(encoder_ffn_dim, d_model)
        self.final_layer_norm = nn.LayerNorm(d_model)
        # [END]

    def forward(
        self,
        hidden_states,
        attention_mask,
        object_queries=None,
    ):
        """
        Args:
            hidden_states (`torch.FloatTensor`): input to the layer of shape `(batch, seq_len, embed_dim)`
            attention_mask (`torch.FloatTensor`): attention mask of size
                `(batch, 1, target_len, source_len)` where padding elements are indicated by very large negative
                values.
            object_queries (`torch.FloatTensor`, *optional*):
                Object queries (also called content embeddings), to be added to the hidden states.
        """
        ##########################################
        # TODO: fill the below incomplete code   #
        ##########################################
        # [START]
        residual =  hidden_states
        hidden_states = self.self_attn(
            hidden_states=hidden_states,
            attention_mask=attention_mask,
            object_queries=object_queries
        )
        # [END]

        ##########################################
        # TODO: complete the forward function    #
        ##########################################
        # [START]
        hidden_states = residual + self.dropout(hidden_states)
        hidden_states = self.self_attn_layer_norm(hidden_states)
        residual = hidden_states
        hidden_states = self.fc2(self.dropout(self.activation_fn(self.fc1(hidden_states))))
        hidden_states = residual + self.dropout(hidden_states)
        hidden_states = self.final_layer_norm(hidden_states)


        # [END]

        if self.training:
            if torch.isinf(hidden_states).any() or torch.isnan(hidden_states).any():
                clamp_value = torch.finfo(hidden_states.dtype).max - 1000
                hidden_states = torch.clamp(hidden_states, min=-clamp_value, max=clamp_value)

        return hidden_states


class DetrEncoder(nn.Module):
    """
    Transformer encoder consisting of *config.encoder_layers* self attention layers. Each layer is a
    [`DetrEncoderLayer`].

    The encoder updates the flattened feature map through multiple self-attention layers.

    Small tweak for DETR:

    - object_queries are added to the forward pass.

    Args:
        config: DetrConfig
    """

    def __init__(
        self,
        encoder_layers,
        encoder_ffn_dim,
        encoder_attention_heads,
        d_model,
        dropout=0.1,
    ):
        super().__init__()

        self.dropout = dropout

        self.layers = nn.ModuleList(
            [
                DetrEncoderLayer(
                    encoder_ffn_dim,
                    encoder_attention_heads,
                    d_model,
                    dropout,
                )
                for _ in range(encoder_layers)
            ]
        )

        # in the original DETR, no layernorm is used at the end of the encoder, as "normalize_before" is set to False by default

    def forward(
        self,
        inputs_embeds=None,
        attention_mask=None,
        object_queries=None,
    ):

        r"""
        Args:
            inputs_embeds (`torch.FloatTensor` of shape `(batch_size, sequence_length, hidden_size)`):
                Flattened feature map (output of the backbone + projection layer) that is passed to the encoder.

            attention_mask (`torch.Tensor` of shape `(batch_size, sequence_length)`, *optional*):
                Mask to avoid performing attention on padding pixel features. Mask values selected in `[0, 1]`:

                - 1 for pixel features that are real (i.e. **not masked**),
                - 0 for pixel features that are padding (i.e. **masked**).

                [What are attention masks?](../glossary#attention-mask)

            object_queries (`torch.FloatTensor` of shape `(batch_size, sequence_length, hidden_size)`):
                Object queries that are added to the queries in each self-attention layer.
        """




        ##########################################
        # TODO: fill the below incomplete code   #
        ##########################################
        # [START]
        hidden_states = inputs_embeds
        hidden_states = nn.functional.dropout(hidden_states, p=self.dropout, training=self.training)
        # [END]
        # print(f"[DEBUG] DetrEncoder forward hidden_states shape: {hidden_states.shape}")
        # print(f"[DEBUG] DetrEncoder forward object_queries: {object_queries.shape if object_queries is not None else None}")


        if attention_mask is not None:
            # [batch_size, seq_len] -> [batch_size, 1, target_seq_len, source_seq_len]
            attention_mask = _prepare_4d_attention_mask(attention_mask, inputs_embeds.dtype)

        for i, encoder_layer in enumerate(self.layers):
            ##################################################################
            # TODO: complete the forward function                            #
            # HINT: add object_queries as extra input to the encoder_layer   #
            ##################################################################
            # [START]
          hidden_states = encoder_layer(
          hidden_states=hidden_states,
          attention_mask=attention_mask,
          object_queries = object_queries
          )

            # [END]

        return hidden_states

