import pandas as pd
results = []


sample_sub = pd.read_csv("sample_submissions.csv", dtype={'image_id': str})
sample_sub_dict = dict(zip(sample_sub["image_id"], sample_sub["PredictionString"]))
image_ids = list(sample_sub["image_id"])
cnt = 0

for images, annots in dataloader_test:
    for i in range(len(annots)):
        image = images[i].unsqueeze(0).to(device).float()
        annot = annots[i]

        height, width = annot['orig_size']
        height, width = height.item(), width.item()

        target_sizes = torch.tensor([[height, width]]).to(device)
        outputs = model(image)
        processed = model.post_process(outputs, threshold=0.30, target_sizes=target_sizes)[0]

        image_id = image_ids[cnt]
        cnt += 1

        if len(processed["scores"]) == 0:
            prediction_str = sample_sub_dict[image_id]
        else:
            prediction_str = ""
            boxes = processed["boxes"].detach().cpu().numpy()
            scores = processed["scores"].detach().cpu().numpy()
            labels = processed["labels"].detach().cpu().numpy()

            for score, label, box in zip(scores, labels, boxes):
                x1, y1, x2, y2 = box
                prediction_str += f"{score:.4f} {int(label)} {x1:.1f} {y1:.1f} {x2:.1f} {y2:.1f} "

        prediction_str = prediction_str.strip()
        results.append({"image_id": image_id, "PredictionString": prediction_str})

# 저장
submission = pd.DataFrame(results)
submission.to_csv("submission.csv", index=False)
print("캐글 제출용 submission.csv 완성!")

